; マップを開いた時に必ず実行されるスクリプト
[initial]

[endinitial]
;===============================================================================
;◆イベント◆

; 初期発生イベント
events = [1, 2, 3, 4, 5]

;-------------------------------------------------------------------------------
*event_1
;[exp] onObjectTrigger

@notice text="There are various types of water area. Some are too deep, and inaccessible even to those wearing shell equipment."

[eventoff]
;-------------------------------------------------------------------------------
*event_2
;[exp] onObjectTrigger

@notice text="When entering the water, first look for a ladder and secure an escape route."

[eventoff]
;-------------------------------------------------------------------------------
*event_3
;[exp] onObjectTrigger

@se f=kacha
@wait time=800
@se f=fence
@switchfence x=8 y=18 way=w arch=gate mode=open
@wait time=1000
@notice text="I heard a door open somewhere!"
@delevent

[eventoff]
;-------------------------------------------------------------------------------
*event_4
;[exp] true

@monster pos=1 name=セイレーン
@monster pos=3 name=セイレーン
@monster pos=5 name=セイレーン
@callbattle bgm=boss gameover=true
@treasure item=貝のネックレス,クラムボトムズ
@delevent

[eventoff]
;-------------------------------------------------------------------------------
*event_5
;[exp] ! party.isSwimming()

@notice text="<y>The floor was completely flooded!<r>Some members couldn't dive, so we hurriedly went up to the upper floor!"
@eval exp='game.moveToFloorVertically(%[map: "水の宮殿１Ｆ", lift: "up"])'

[eventoff]
;-------------------------------------------------------------------------------
